import React, { useEffect, useRef, useState, useMemo } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { ImageUpload } from "@/components/input/ImageUpload";
import {
  Lock,
  ArrowRight,
  LayoutTemplate,
  Globe,
  MessageCircle,
  Eye,
  EyeOff,
  Twitter,
  Search,
  Loader2,
  CheckCircle2,
  XCircle,
} from "lucide-react";
import { useTranslation } from "@/i18n";
import {
  fetchDexBrokerDetail,
  fetchDexCreatorDexStatus,
  fetchDexNetworks,
  updateDexBoardVisibility,
  updateDexSocialCard,
  type DexBrokerDetail,
  type DexCreatorDexStatus,
  type NetworkInfo,
} from "@/services/orderly";
import { type Profile, getProfile } from "@/utils/branding-shared";
import { LocalizedLink } from "@/utils/localizedRoute";
import { LeaderboardCard } from "@/components/leaderboard/LeaderboardCard";

interface DexCardConfig {
  description: string;
  banner: string | null;
  logo: string | null;
  tokenAddress: string;
  tokenChain: string;
  telegramLink: string;
  discordLink: string;
  xLink: string;
  websiteUrl: string;
  showInLeaderboard: boolean;
}

const defaultConfig: DexCardConfig = {
  description: "",
  banner: null,
  logo: null,
  tokenAddress: "",
  tokenChain: "",
  telegramLink: "",
  discordLink: "",
  xLink: "",
  websiteUrl: "",
  showInLeaderboard: true,
};

function configFromStatus(status: DexCreatorDexStatus): DexCardConfig {
  return {
    description: status.description ?? "",
    banner: status.banner ?? null,
    logo: status.logo ?? null,
    tokenAddress: status.tokenAddress ?? "",
    tokenChain: status.tokenChain ?? "",
    telegramLink: status.telegramLink ?? "",
    discordLink: status.discordLink ?? "",
    xLink: status.xLink ?? "",
    websiteUrl: status.websiteUrl ?? "",
    showInLeaderboard: status.showOnBoard ?? true,
  };
}

function pickString(...values: unknown[]): string | null {
  for (const value of values) {
    if (typeof value === "string" && value.trim()) return value.trim();
  }
  return null;
}

async function appendDataUrlFile(
  formData: FormData,
  key: string,
  value: string | null,
  filename: string
) {
  if (value === null) {
    formData.append(key, "");
    return;
  }
  if (!value || !value.startsWith("data:")) return;
  const blob = await fetch(value).then(response => response.blob());
  formData.append(key, blob, filename);
}

function appendTrimmed(formData: FormData, key: string, value: string) {
  const trimmed = value.trim();
  if (trimmed) formData.append(key, trimmed);
}

async function buildSocialCardFormData(config: DexCardConfig) {
  const formData = new FormData();
  appendTrimmed(formData, "description", config.description);
  appendTrimmed(formData, "tokenAddress", config.tokenAddress);
  appendTrimmed(formData, "tokenChain", config.tokenChain);
  appendTrimmed(formData, "telegramLink", config.telegramLink);
  appendTrimmed(formData, "discordLink", config.discordLink);
  appendTrimmed(formData, "xLink", config.xLink);
  appendTrimmed(formData, "websiteUrl", config.websiteUrl);
  await appendDataUrlFile(formData, "banner", config.banner, "banner.webp");
  await appendDataUrlFile(formData, "logo", config.logo, "logo.webp");
  return formData;
}

export default function DexCardPage() {
  const { t } = useTranslation();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [dexStatus, setDexStatus] = useState<DexCreatorDexStatus | null>(null);
  const [config, setConfig] = useState<DexCardConfig>(defaultConfig);
  const [leaderboardDetail, setLeaderboardDetail] =
    useState<DexBrokerDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [visibilityUpdating, setVisibilityUpdating] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  const [networks, setNetworks] = useState<NetworkInfo[]>([]);
  const [isLoadingNetworks, setIsLoadingNetworks] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [networkSearchQuery, setNetworkSearchQuery] = useState("");
  const dropdownRef = useRef<HTMLDivElement>(null);
  const hasValidatedOnLoad = useRef(false);

  const [isValidatingToken, setIsValidatingToken] = useState(false);
  const [tokenValidation, setTokenValidation] = useState<{
    isValid: boolean;
    tokenInfo?: {
      attributes: {
        name: string;
        symbol: string;
        image_url?: string;
        price_usd?: string;
        market_cap_usd?: string;
      };
    };
    error?: string;
  } | null>(null);

  const filteredNetworks = useMemo(() => {
    if (!networkSearchQuery.trim()) return networks;
    const query = networkSearchQuery.toLowerCase();
    return networks.filter(
      network =>
        network.name.toLowerCase().includes(query) ||
        network.id.toLowerCase().includes(query)
    );
  }, [networks, networkSearchQuery]);

  useEffect(() => {
    setProfile(getProfile());

    let cancelled = false;
    setLoading(true);
    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled) return;
        setDexStatus(status);
        if (status && status.exists !== false) {
          setConfig(configFromStatus(status));
          const brokerId =
            status.brokerId && status.brokerId !== "demo"
              ? status.brokerId
              : null;
          if (brokerId) {
            fetchDexBrokerDetail(brokerId, "30d")
              .then(detail => {
                if (!cancelled) setLeaderboardDetail(detail);
              })
              .catch(() => {
                if (!cancelled) setLeaderboardDetail(null);
              });
          }
        }
      })
      .catch(() => {
        if (!cancelled) setDexStatus(null);
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    setIsLoadingNetworks(true);
    fetchDexNetworks()
      .then(all => {
        if (!cancelled) {
          const sorted = all.sort((a, b) => a.name.localeCompare(b.name));
          setNetworks(sorted);
        }
      })
      .catch(() => {})
      .finally(() => {
        if (!cancelled) setIsLoadingNetworks(false);
      });
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (config.tokenChain && networks.length > 0) {
      const selected = networks.find(n => n.id === config.tokenChain);
      if (selected) setNetworkSearchQuery(selected.name);
    }
  }, [config.tokenChain, networks]);

  useEffect(() => {
    if (hasValidatedOnLoad.current) return;
    if (!networks.length) return;
    const address = config.tokenAddress.trim();
    const chain = config.tokenChain.trim();
    if (address && chain) {
      hasValidatedOnLoad.current = true;
      validateToken(address, chain);
    }
  }, [config.tokenAddress, config.tokenChain, networks.length]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const isGraduated = !!(profile?.graduated || dexStatus?.isGraduated);
  const dexId = dexStatus?.id || profile?.dexId || null;
  const brokerId =
    (dexStatus?.brokerId && dexStatus.brokerId !== "demo"
      ? dexStatus.brokerId
      : null) ||
    (profile?.brokerId && profile.brokerId !== "demo"
      ? profile.brokerId
      : null);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  async function handleToggleLeaderboard() {
    if (!dexId) {
      showToast("DEX ID not found. Please reload the page.");
      return;
    }

    const previous = config.showInLeaderboard;
    const next = !previous;
    setConfig(prev => ({ ...prev, showInLeaderboard: next }));
    setVisibilityUpdating(true);

    try {
      await updateDexBoardVisibility(dexId, next);
      const refreshed = await fetchDexCreatorDexStatus({ force: true });
      if (refreshed && refreshed.exists !== false) {
        setDexStatus(refreshed);
        setConfig(configFromStatus(refreshed));
      }
      showToast(
        next
          ? t("dexCard.visibleInLeaderboard")
          : t("dexCard.hiddenFromLeaderboard")
      );
    } catch (error) {
      setConfig(prev => ({ ...prev, showInLeaderboard: previous }));
      showToast(
        error instanceof Error
          ? error.message
          : "Failed to update DEX profile visibility."
      );
    } finally {
      setVisibilityUpdating(false);
    }
  }

  const validateToken = async (address: string, chain: string) => {
    if (!address.trim() || !chain.trim()) {
      setTokenValidation(null);
      return;
    }
    setIsValidatingToken(true);
    try {
      const response = await fetch(
        `https://api.geckoterminal.com/api/v2/networks/${chain}/tokens/${address}`
      );
      if (response.ok) {
        const data = await response.json();
        setTokenValidation({ isValid: true, tokenInfo: data.data });
      } else {
        setTokenValidation({
          isValid: false,
          error: t("dexCard.error.tokenNotFound"),
        });
      }
    } catch {
      setTokenValidation({
        isValid: false,
        error: t("dexCard.error.tokenValidateFailed"),
      });
    } finally {
      setIsValidatingToken(false);
    }
  };

  const handleTokenAddressChange = (value: string) => {
    setConfig(prev => ({ ...prev, tokenAddress: value }));
    if (tokenValidation) setTokenValidation(null);
  };

  const handleTokenAddressBlur = () => {
    if (config.tokenAddress.trim() && config.tokenChain.trim()) {
      validateToken(config.tokenAddress, config.tokenChain);
    }
  };

  const handleNetworkSearch = (query: string) => {
    setNetworkSearchQuery(query);
    setIsDropdownOpen(true);
  };

  const selectNetwork = (network: NetworkInfo) => {
    setConfig(prev => ({ ...prev, tokenChain: network.id }));
    setNetworkSearchQuery(network.name);
    setIsDropdownOpen(false);
    if (config.tokenAddress.trim()) {
      validateToken(config.tokenAddress, network.id);
    }
  };

  async function handleSave() {
    if (!dexId) {
      showToast("DEX ID not found. Please reload the page.");
      return;
    }

    setSaving(true);
    try {
      const formData = await buildSocialCardFormData(config);
      await updateDexSocialCard(formData);
      if (config.showInLeaderboard !== dexStatus?.showOnBoard) {
        await updateDexBoardVisibility(dexId, config.showInLeaderboard);
      }

      const [refreshedStatus, refreshedDetail] = await Promise.all([
        fetchDexCreatorDexStatus({ force: true }),
        brokerId
          ? fetchDexBrokerDetail(brokerId, "30d").catch(() => null)
          : Promise.resolve(null),
      ]);

      if (refreshedStatus && refreshedStatus.exists !== false) {
        setDexStatus(refreshedStatus);
        setConfig(configFromStatus(refreshedStatus));
      }
      if (refreshedDetail) setLeaderboardDetail(refreshedDetail);

      showToast(t("dexCard.savedSuccessfully"));
    } catch (error) {
      showToast(
        error instanceof Error ? error.message : "Failed to save DEX profile."
      );
    } finally {
      setSaving(false);
    }
  }

  const previewName =
    pickString(
      leaderboardDetail?.dex?.brokerName,
      dexStatus?.brokerName,
      profile?.builderName
    ) || "DEX";

  const tokenMatches =
    config.tokenAddress &&
    config.tokenChain &&
    leaderboardDetail?.dex &&
    (leaderboardDetail.dex.tokenAddress || "").toLowerCase() ===
      config.tokenAddress.toLowerCase() &&
    (leaderboardDetail.dex.tokenChain || "").toLowerCase() ===
      config.tokenChain.toLowerCase();

  const validatedTokenAttr = tokenValidation?.isValid
    ? tokenValidation.tokenInfo?.attributes
    : null;

  const previewTokenSymbol =
    validatedTokenAttr?.symbol ||
    (tokenMatches ? leaderboardDetail!.dex.tokenSymbol || "" : "");
  const previewTokenName =
    validatedTokenAttr?.name ||
    (tokenMatches ? leaderboardDetail!.dex.tokenName || "" : "");
  const previewTokenImageUrl =
    validatedTokenAttr?.image_url ||
    (tokenMatches ? leaderboardDetail!.dex.tokenImageUrl : null) ||
    null;
  const previewDexUrl =
    leaderboardDetail?.dex?.dexUrl || dexStatus?.dexUrl || "";

  return (
    <PageShell pageTitle={t("navigation.dexCard")}>
      <div>
        {!isGraduated ? (
          <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-(--line-subtle) bg-(--bg-surface-secondary) p-10 text-center">
            <div className="mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-(--bg-hover) text-(--fg-secondary)">
              <Lock className="h-6 w-6" />
            </div>
            <h4 className="mb-1 text-base font-medium text-(--fg-primary)">
              {t("dexCard.locked")}
            </h4>
            <p className="mb-5 max-w-sm text-sm text-(--fg-secondary)">
              {t("dexCard.lockedDesc")}
            </p>
            <LocalizedLink
              to="/home"
              className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              {t("graduation.goToDashboard")}
              <ArrowRight className="h-4 w-4" />
            </LocalizedLink>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
              <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                  <h3 className="text-base font-medium text-(--fg-primary)">
                    {t("navigation.dexCard")}
                  </h3>
                  <p className="mt-0.5 text-sm text-(--fg-secondary)">
                    {t("dexCard.manageLeaderboardAppearance")}
                  </p>
                </div>
                <button
                  type="button"
                  onClick={handleToggleLeaderboard}
                  disabled={visibilityUpdating}
                  className={`inline-flex items-center gap-2 self-start rounded-lg border px-4 py-2.5 text-sm font-medium transition-colors disabled:cursor-not-allowed disabled:opacity-60 ${
                    config.showInLeaderboard
                      ? "border-[rgba(29,246,181,0.25)] bg-[rgba(29,246,181,0.08)] text-[#1DF6B5]"
                      : "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)"
                  }`}
                >
                  {config.showInLeaderboard ? (
                    <Eye className="h-4 w-4" />
                  ) : (
                    <EyeOff className="h-4 w-4" />
                  )}
                  {config.showInLeaderboard
                    ? t("dexCard.visibleInLeaderboardLabel")
                    : t("dexCard.hiddenFromLeaderboardLabel")}
                </button>
              </div>
            </div>

            {loading ? (
              <div className="flex items-center justify-center py-12">
                <span className="inline-block h-8 w-8 animate-spin rounded-full border-2 border-(--line-subtle) border-t-(--fg-brand)" />
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
                <div className="space-y-5 rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
                  <div>
                    <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                      {t("common.description")}
                    </label>
                    <textarea
                      value={config.description}
                      onChange={e =>
                        setConfig(prev => ({
                          ...prev,
                          description: e.target.value,
                        }))
                      }
                      maxLength={150}
                      rows={3}
                      placeholder={t("dexCard.descriptionPlaceholder")}
                      className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors placeholder:text-(--fg-placeholder) focus:border-(--line-brand)"
                    />
                    <div className="mt-1 text-right text-xs text-(--fg-secondary)">
                      {config.description.length}/150
                    </div>
                  </div>

                  <div className="grid grid-cols-1 gap-5 sm:grid-cols-2">
                    <ImageUpload
                      label={t("dexCard.bannerImage")}
                      value={config.banner}
                      onChange={value =>
                        setConfig(prev => ({ ...prev, banner: value }))
                      }
                      onClear={() =>
                        setConfig(prev => ({ ...prev, banner: null }))
                      }
                      accept="image/png,image/jpeg,image/webp,image/gif"
                    />
                    <ImageUpload
                      label={t("dexCard.logoImage")}
                      value={config.logo}
                      onChange={value =>
                        setConfig(prev => ({ ...prev, logo: value }))
                      }
                      onClear={() =>
                        setConfig(prev => ({ ...prev, logo: null }))
                      }
                      accept="image/png,image/jpeg,image/webp,image/gif"
                    />
                  </div>

                  <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                    <div>
                      <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                        {t("dexConfig.tokenAddress")}
                      </label>
                      <input
                        type="text"
                        value={config.tokenAddress}
                        onChange={e => handleTokenAddressChange(e.target.value)}
                        onBlur={handleTokenAddressBlur}
                        placeholder="0x..."
                        className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors placeholder:text-(--fg-placeholder) focus:border-(--line-brand)"
                      />
                      {isValidatingToken && (
                        <div className="mt-2 flex items-center gap-1.5 text-xs text-(--fg-secondary)">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          {t("common.loading")}
                        </div>
                      )}
                      {tokenValidation && !isValidatingToken && (
                        <div className="mt-2">
                          {tokenValidation.isValid &&
                          tokenValidation.tokenInfo ? (
                            <div className="flex items-center gap-2 rounded-lg bg-(--bg-surface-secondary) px-3 py-2">
                              {tokenValidation.tokenInfo.attributes
                                .image_url && (
                                <img
                                  src={
                                    tokenValidation.tokenInfo.attributes
                                      .image_url
                                  }
                                  alt=""
                                  className="h-5 w-5 rounded-full object-cover"
                                />
                              )}
                              <div className="min-w-0 flex-1">
                                <div className="text-xs font-medium text-(--fg-primary)">
                                  {tokenValidation.tokenInfo.attributes.symbol}
                                </div>
                                <div className="truncate text-[11px] text-(--fg-secondary)">
                                  {tokenValidation.tokenInfo.attributes.name}
                                  {tokenValidation.tokenInfo.attributes
                                    .price_usd &&
                                    ` · $${Number(tokenValidation.tokenInfo.attributes.price_usd).toLocaleString()}`}
                                </div>
                              </div>
                              <CheckCircle2 className="h-4 w-4 shrink-0 text-green-500" />
                            </div>
                          ) : (
                            <div className="flex items-center gap-1.5 text-xs text-red-400">
                              <XCircle className="h-3.5 w-3.5 shrink-0" />
                              {tokenValidation.error}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                    <div ref={dropdownRef} className="relative">
                      <label className="mb-1.5 block text-sm text-(--fg-secondary)">
                        {t("common.chain")}
                      </label>
                      <div className="relative">
                        <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-(--fg-secondary)" />
                        <input
                          type="text"
                          value={networkSearchQuery}
                          onChange={e => handleNetworkSearch(e.target.value)}
                          onFocus={() => setIsDropdownOpen(true)}
                          placeholder={t("dexCard.tokenChain.placeholder")}
                          disabled={isLoadingNetworks}
                          className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) pl-9 pr-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors placeholder:text-(--fg-placeholder) focus:border-(--line-brand) disabled:opacity-60"
                        />
                      </div>
                      {isDropdownOpen && filteredNetworks.length > 0 && (
                        <div className="absolute z-20 mt-1 max-h-60 w-full overflow-auto rounded-lg border border-(--line-subtle) bg-(--bg-surface-primary) shadow-xl">
                          {filteredNetworks.map(network => (
                            <button
                              key={network.id}
                              type="button"
                              onClick={() => selectNetwork(network)}
                              className={`w-full px-3 py-2 text-left text-sm transition-colors hover:bg-(--bg-hover) ${
                                config.tokenChain === network.id
                                  ? "bg-(--bg-brand)/10 text-(--fg-brand)"
                                  : "text-(--fg-primary)"
                              }`}
                            >
                              {network.name}
                              <span className="ml-2 text-xs text-(--fg-secondary)">
                                {network.id}
                              </span>
                            </button>
                          ))}
                        </div>
                      )}
                      {isDropdownOpen &&
                        !isLoadingNetworks &&
                        filteredNetworks.length === 0 && (
                          <div className="absolute z-20 mt-1 w-full rounded-lg border border-(--line-subtle) bg-(--bg-surface-primary) px-3 py-2 text-sm text-(--fg-secondary) shadow-xl">
                            {t("dexCard.tokenChain.noResults")}
                          </div>
                        )}
                      {isLoadingNetworks && (
                        <div className="mt-1 flex items-center gap-1.5 text-xs text-(--fg-secondary)">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          {t("common.loading")}
                        </div>
                      )}
                    </div>
                  </div>

                  <div>
                    <label className="mb-2 block text-sm text-(--fg-secondary)">
                      {t("dexCard.socialLinks")}
                    </label>
                    <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                      <SocialInput
                        icon={MessageCircle}
                        placeholder="Telegram URL"
                        value={config.telegramLink}
                        onChange={v =>
                          setConfig(prev => ({ ...prev, telegramLink: v }))
                        }
                      />
                      <SocialInput
                        icon={LayoutTemplate}
                        placeholder="Discord URL"
                        value={config.discordLink}
                        onChange={v =>
                          setConfig(prev => ({ ...prev, discordLink: v }))
                        }
                      />
                      <SocialInput
                        icon={Twitter}
                        placeholder="X (Twitter) URL"
                        value={config.xLink}
                        onChange={v =>
                          setConfig(prev => ({ ...prev, xLink: v }))
                        }
                      />
                      <SocialInput
                        icon={Globe}
                        placeholder="Website URL"
                        value={config.websiteUrl}
                        onChange={v =>
                          setConfig(prev => ({ ...prev, websiteUrl: v }))
                        }
                      />
                    </div>
                  </div>

                  <button
                    type="button"
                    onClick={handleSave}
                    disabled={saving}
                    className="rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
                    style={{ background: "var(--bg-brand-grad)" }}
                  >
                    {saving ? t("common.saving") : t("common.save")}
                  </button>
                </div>

                <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
                  <h4 className="mb-4 text-sm font-medium text-(--fg-primary)">
                    {t("common.preview")}
                  </h4>
                  <LeaderboardCard
                    dex={{
                      brokerName: previewName,
                      description: config.description || null,
                      banner: config.banner,
                      logo: config.logo,
                      tokenAddress: config.tokenAddress || null,
                      tokenChain: config.tokenChain || null,
                      tokenSymbol: previewTokenSymbol || null,
                      tokenName: previewTokenName || null,
                      tokenImageUrl: previewTokenImageUrl || null,
                      telegramLink: config.telegramLink || null,
                      discordLink: config.discordLink || null,
                      xLink: config.xLink || null,
                      websiteUrl: config.websiteUrl || null,
                      dexUrl: previewDexUrl || null,
                    }}
                    labels={{
                      unnamedDex: previewName,
                      noDescription: t("board.noDescription"),
                      volumeForPeriod: "—",
                      builderRevenue: "—",
                      website: t("dexConfig.website"),
                      telegram: "Telegram",
                      discord: "Discord",
                      x: "X",
                      dex: "DEX",
                    }}
                  />
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}

function SocialInput({
  icon: Icon,
  placeholder,
  value,
  onChange,
}: {
  icon: React.ElementType;
  placeholder: string;
  value: string;
  onChange: (val: string) => void;
}) {
  return (
    <div className="flex items-center gap-2 rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 transition-colors focus-within:border-(--line-brand)">
      <Icon className="h-4 w-4 shrink-0 text-(--fg-secondary)" />
      <input
        type="url"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        className="min-w-0 flex-1 bg-transparent text-sm text-(--fg-primary) outline-none placeholder:text-(--fg-placeholder)"
      />
    </div>
  );
}
